const raw = $input.first().json;

let statsData = [];

if (raw?.result?.data && Array.isArray(raw.result.data)) {
  statsData = raw.result.data;
} else if (raw?.data?.result?.data && Array.isArray(raw.data.result.data)) {
  statsData = raw.data.result.data;
} else if (raw?.data && Array.isArray(raw.data)) {
  statsData = raw.data;
} else if (Array.isArray(raw)) {
  statsData = raw;
}

if (statsData.length === 0) {
  return [{ json: { _empty: true, _raw_keys: Object.keys(raw || {}), _raw_sample: JSON.stringify(raw).substring(0, 500) } }];
}

const results = statsData
  .filter(d => d.ad_id && d.ad_id > 0)
  .map(d => {
    const spend = parseFloat(d.money) || parseFloat(d.total_expenses) || 0;
    const revenue = parseFloat(d.postbacks_confirmed_money) || 0;
    const clicks = parseInt(d.clicks_count) || 0;
    const shows = parseInt(d.shows_count) || 0;
    const confirmedShows = parseInt(d.confirmed_shows_count) || 0;
    const postbacks = parseInt(d.postbacks_total_count) || 0;

    const roi = spend > 0 ? ((revenue - spend) / spend * 100) : 0;
    const profit = revenue - spend;
    const ctr = shows > 0 ? (clicks / shows * 100) : 0;
    const cpc = clicks > 0 ? (spend / clicks) : 0;
    const date = d.date || $now.toFormat('yyyy-MM-dd');

    return {
      json: {
        ad_id: parseInt(d.ad_id),
        date: date,
        shows: shows,
        confirmed_shows: confirmedShows,
        clicks: clicks,
        money: Math.round(spend * 10000) / 10000,
        postbacks_count: postbacks,
        postbacks_confirmed_money: Math.round(revenue * 10000) / 10000,
        ctr: Math.round(ctr * 10000) / 10000,
        cpc: Math.round(cpc * 10000) / 10000,
        roi: Math.round(roi * 100) / 100,
        profit: Math.round(profit * 10000) / 10000
      }
    };
  });

return results.length > 0 ? results : [{ json: { _empty: true } }];

const items = $input.all();

// Filter valid rows and build UPDATE statements
const updates = items
  .filter(i => i.json.ad_id && !isNaN(parseInt(i.json.ad_id)) && i.json.lead_date)
  .map(i => {
    const adId = parseInt(i.json.ad_id);
    const date = i.json.lead_date;
    const leads = parseInt(i.json.crm_leads) || 0;
    const depositors = parseInt(i.json.crm_depositors) || 0;
    const revenue = parseFloat(i.json.crm_revenue) || 0;
    return {
      json: {
        ad_id: adId,
        date: typeof date === 'string' ? date : new Date(date).toISOString().slice(0, 10),
        crm_leads: leads,
        crm_depositors: depositors,
        crm_revenue: revenue
      }
    };
  });

if (updates.length === 0) {
  return [{ json: { _empty: true } }];
}

return updates;
